('economics:3-2-low-unemployment:match:39c77ff4', 'economics', 'economics:3-2-low-unemployment', '3.2 Low Unemployment', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Workforce”?", "options": ["Being willing and able to work but unable to find a job", "Everyone able and willing to work — the denominator in the rate", "Measures unemployment by counting those receiving Jobseeker''s Allowance", "The total number of people unemployed"]}'::jsonb, '{"answer": 1, "explain": "“Workforce” means: Everyone able and willing to work — the denominator in the rate"}'::jsonb),
