('economics:3-3-fair-distribution-of-income:match:be9faf19', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Income”?", "options": ["Reduces wealth passed on when someone dies, breaking up large estates", "The legal pay floor for workers aged 23 and over", "A flow of money received over time for the services of a factor of production", "Income earned from letting out an owned asset such as a second home"]}'::jsonb, '{"answer": 2, "explain": "“Income” means: A flow of money received over time for the services of a factor of production"}'::jsonb),
('economics:3-3-fair-distribution-of-income:match:f43b64a9', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Wealth”?", "options": ["The slice of income taxed at 0% before any tax is paid", "A stock of assets owned by a person, group or country", "A share of a company''s profits paid to its shareholders", "Charges a higher rate of tax on higher incomes"]}'::jsonb, '{"answer": 1, "explain": "“Wealth” means: A stock of assets owned by a person, group or country"}'::jsonb),
