('economics:3-3-fair-distribution-of-income:match:8783ddea', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dividends”?", "options": ["Lacking the basic necessities — food, shelter, clothing, sanitation", "A share of a company''s profits paid to its shareholders", "A household with less than 60% of median income", "The percentage of total income going to a subgroup of the population"]}'::jsonb, '{"answer": 1, "explain": "“Dividends” means: A share of a company''s profits paid to its shareholders"}'::jsonb),
('economics:3-3-fair-distribution-of-income:match:5fa01cb5', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Absolute poverty”?", "options": ["Lacking the basic necessities — food, shelter, clothing, sanitation", "A flow of money received over time for the services of a factor of production", "A household with less than 60% of median income", "A share of a company''s profits paid to its shareholders"]}'::jsonb, '{"answer": 0, "explain": "“Absolute poverty” means: Lacking the basic necessities — food, shelter, clothing, sanitation"}'::jsonb),
('economics:3-3-fair-distribution-of-income:match:38825501', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Relative poverty”?", "options": ["A share of a company''s profits paid to its shareholders", "A household with less than 60% of median income", "A stock of assets owned by a person, group or country", "Lacking the basic necessities — food, shelter, clothing, sanitation"]}'::jsonb, '{"answer": 1, "explain": "“Relative poverty” means: A household with less than 60% of median income"}'::jsonb),
('economics:3-3-fair-distribution-of-income:match:c10cec64', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Progressive tax”?", "options": ["Charges a higher rate of tax on higher incomes", "A share of a company''s profits paid to its shareholders", "Lacking the basic necessities — food, shelter, clothing, sanitation", "Takes a higher proportion of income from low earners, e.g. VAT"]}'::jsonb, '{"answer": 0, "explain": "“Progressive tax” means: Charges a higher rate of tax on higher incomes"}'::jsonb),
