('economics:3-3-fair-distribution-of-income:match:0ddc35c2', 'economics', 'economics:3-3-fair-distribution-of-income', '3.3 Fair Distribution of Income', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Inheritance tax”?", "options": ["A share of a company''s profits paid to its shareholders", "Charges a higher rate of tax on higher incomes", "Takes a higher proportion of income from low earners, e.g. VAT", "Reduces wealth passed on when someone dies, breaking up large estates"]}'::jsonb, '{"answer": 3, "explain": "“Inheritance tax” means: Reduces wealth passed on when someone dies, breaking up large estates"}'::jsonb),
